@using Microsoft.AspNetCore.Components.Authorization

<RedirectToLogin />

@code {
    [CascadingParameter]
    private HttpContext HttpContext { get; set; } = default!;

    protected override void OnInitialized()
    {
        HttpContext.Response.Redirect($"/account/login?returnUrl={Uri.EscapeDataString(HttpContext.Request.Path)}");
    }
}

@page "/account/login"
@using Microsoft.AspNetCore.Identity
@inject SignInManager<IdentityUser> SignInManager
@inject NavigationManager Navigation

<PageTitle>Login</PageTitle>

<div class="row justify-content-center mt-5">
    <div class="col-md-4">
        <h3>Login</h3>
        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }
        <EditForm Model="Input" FormName="login" OnValidSubmit="LoginUser" method="post">
            <DataAnnotationsValidator />
            <div class="mb-3">
                <label class="form-label">Email</label>
                <InputText @bind-Value="Input.Email" class="form-control" />
                <ValidationMessage For="() => Input.Email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Password</label>
                <InputText @bind-Value="Input.Password" type="password" class="form-control" />
                <ValidationMessage For="() => Input.Password" />
            </div>
            <button type="submit" class="btn btn-primary w-100">Sign in</button>
        </EditForm>
    </div>
</div>

@code {
    private string? errorMessage;

    [CascadingParameter]
    private HttpContext HttpContext { get; set; } = default!;

    [SupplyParameterFromForm]
    private LoginInput Input { get; set; } = new();

    [SupplyParameterFromQuery]
    private string? ReturnUrl { get; set; }

    private async Task LoginUser()
    {
        var result = await SignInManager.PasswordSignInAsync(Input.Email, Input.Password, isPersistent: true, lockoutOnFailure: false);
        if (result.Succeeded)
        {
            var url = !string.IsNullOrEmpty(ReturnUrl) ? ReturnUrl : "/";
            Navigation.NavigateTo(url, forceLoad: true);
        }
        else
        {
            errorMessage = "Invalid email or password.";
        }
    }

    private sealed class LoginInput
    {
        [System.ComponentModel.DataAnnotations.Required]
        [System.ComponentModel.DataAnnotations.EmailAddress]
        public string Email { get; set; } = "";

        [System.ComponentModel.DataAnnotations.Required]
        [System.ComponentModel.DataAnnotations.DataType(System.ComponentModel.DataAnnotations.DataType.Password)]
        public string Password { get; set; } = "";
    }
}

@page "/account/logout"
@using Microsoft.AspNetCore.Identity
@inject SignInManager<IdentityUser> SignInManager
@inject NavigationManager Navigation

@code {
    [CascadingParameter]
    private HttpContext HttpContext { get; set; } = default!;

    protected override async Task OnInitializedAsync()
    {
        await SignInManager.SignOutAsync();
        Navigation.NavigateTo("/", forceLoad: true);
    }
}

@page "/admin/users"
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Identity
@attribute [Authorize(Roles = "Admin")]
@inject UserManager<IdentityUser> UserManager

<PageTitle>User Management</PageTitle>

<h3>User Management</h3>

@if (users is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Email</th>
                <th>Roles</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var (user, roles) in users)
            {
                <tr>
                    <td>@user.Email</td>
                    <td>@string.Join(", ", roles)</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<(IdentityUser User, IList<string> Roles)>? users;

    protected override async Task OnInitializedAsync()
    {
        var allUsers = UserManager.Users.ToList();
        var result = new List<(IdentityUser, IList<string>)>();
        foreach (var user in allUsers)
        {
            var roles = await UserManager.GetRolesAsync(user);
            result.Add((user, roles));
        }
        users = result;
    }
}

